    roadmap: [{level:1,title:"TypeScript Basics",subtopics:["Type Annotations","Basic Types (string, number, boolean)","Arrays & Tuples","Enums","Functions & Return Types","Any vs Unknown","Type Assertions"]},{level:2,title:"Interfaces & Objects",subtopics:["Interface Definitions","Optional & Readonly Properties","Extending Interfaces","Type Aliases vs Interfaces","Index Signatures","Intersection & Union Types","Discriminated Unions"]},{level:3,title:"Generics & Advanced Types",subtopics:["Generic Functions","Generic Constraints","Mapped Types","Conditional Types","Template Literal Types","Utility Types (Partial, Pick, Omit)","Type Guards & Narrowing"]},{level:4,title:"Classes & Modules",subtopics:["Classes with Access Modifiers","Abstract Classes","Decorators (Experimental)","Module Resolution","Ambient Declarations","Declaration Files (.d.ts)","Namespace vs Module"]},{level:5,title:"Configuration & Tooling",subtopics:["tsconfig.json Deep Dive","Strict Mode Options","Path Aliases","Project References","Build & Watch Modes","ESLint with TypeScript","Declaration Map & Source Maps"]}],
    resources: [{type:"W3Schools",title:"Learn TypeScript on W3Schools",desc:"Interactive TypeScript tutorial with examples and exercises.",link:"https://www.w3schools.com/typescript/"},{type:"Documentation",title:"TypeScript Official Handbook",desc:"Comprehensive guide from the TypeScript team.",link:"https://www.typescriptlang.org/docs/handbook/"},{type:"Documentation",title:"TypeScript Playground",desc:"Try TypeScript in the browser with live compilation.",link:"https://www.typescriptlang.org/play"},{type:"Tutorials",title:"TypeScript Deep Dive",desc:"Free online book covering TS in depth.",link:"https://basarat.gitbook.io/typescript/"},{type:"Tutorials",title:"Matt Pocock - Total TypeScript",desc:"Advanced TypeScript patterns and tutorials.",link:"https://www.totaltypescript.com/"},{type:"Videos",title:"Fireship - TypeScript in 100 Seconds",desc:"Quick TypeScript overview and rationale.",link:"https://www.youtube.com/watch?v=BwuLxPH8IDs"},{type:"Videos",title:"Traversy Media - TS Crash Course",desc:"Practical TypeScript fundamentals for web devs.",link:"https://www.youtube.com/watch?v=rAYkCVN0aeM"},{type:"Books",title:"Programming TypeScript (2nd Ed)",desc:"Deep dive into TypeScript by Boris Cherny.",link:"https://www.amazon.com/Programming-TypeScript-Your-JavaScript-Applications/dp/1492037656"},{type:"Books",title:"Effective TypeScript",desc:"62 specific ways to improve your TypeScript.",link:"https://www.amazon.com/Effective-TypeScript-Improve-Type-Programs/dp/1492037659"}],
    projects: [{diff:"Beginner",name:"Todo App with Types",desc:"A typed todo application with localStorage.",skills:["Type Annotations","Interfaces","DOM Manipulation"]},{diff:"Beginner",name:"Calculator with Types",desc:"A fully typed calculator with generics.",skills:["Functions","Generics","Type Assertions"]},{diff:"Intermediate",name:"API Client Library",desc:"A typed HTTP client library for REST APIs.",skills:["Generics","Utility Types","Error Handling"]},{diff:"Intermediate",name:"State Management Library",desc:"A mini Redux-like state management with types.",skills:["Discriminated Unions","Mapped Types","Generics"]},{diff:"Advanced",name:"ORM Query Builder",desc:"A type-safe SQL query builder with fluent API.",skills:["Conditional Types","Template Literals","Chaining"]},{diff:"Advanced",name:"Component Library",desc:"A typed React component library with Storybook.",skills:["Generic Components","Props Typing","Distribution"]}],
    interviewQuestions: [{q:"What is the difference between type and interface?",a:"Interfaces support declaration merging and extending. Types support unions, intersections, and mapped types. Interfaces are slightly better for performance in large codebases. Both are interchangeable for most use cases.",diff:"Medium"},{q:"Explain conditional types.",a:"Conditional types follow the pattern T extends U ? X : Y. They allow type-level logic, enabling types to be computed based on other types. Used extensively in utility types like Exclude, Extract, and NonNullable.",diff:"Hard"},{q:"What are utility types?",a:"Built-in types like Partial<T>, Required<T>, Pick<T,K>, Omit<T,K>, Record<K,V>, Readonly<T>. They transform existing types for common use cases, reducing boilerplate and improving type safety.",diff:"Easy"},{q:"Explain type narrowing.",a:"TypeScript narrows types through control flow: typeof checks, instanceof, truthiness, equality, custom type guards, and discriminated unions. This lets the compiler understand which types are possible at each point in code.",diff:"Medium"},{q:"What is the 'unknown' type and when to use it?",a:"unknown is the type-safe counterpart to any. All operations on unknown require type checking first. Use it for values where you don't know the type at compile time but want to enforce safe handling.",diff:"Easy"},{q:"How does TypeScript handle module resolution?",a:"Module resolution follows Node.js conventions (node_modules), with options: classic (for legacy), node (default), bundler, and node16/nodenext for ESM. Path mapping and baseUrl allow custom module paths.",diff:"Hard"}],
