    projects: [{diff:"Beginner",name:"Employee Database",desc:"Design and query an employee management database.",skills:["CREATE TABLE","JOINs","Aggregations"]},{diff:"Beginner",name:"Sales Report Queries",desc:"Write complex queries to generate sales reports.",skills:["GROUP BY","Subqueries","Window Functions"]},{diff:"Intermediate",name:"Library Management System",desc:"Full database for a library with borrowing tracking.",skills:["Normalization","Indexes","Stored Procedures"]},{diff:"Intermediate",name:"Data Migration Script",desc:"Migrate data between schemas with transformations.",skills:["CTEs","CASE","Bulk Operations"]},{diff:"Advanced",name:"Analytics Dashboard Backend",desc:"Optimized queries powering a real-time dashboard.",skills:["Window Functions","Materialized Views","Partitioning"]},{diff:"Advanced",name:"Database Performance Tuner",desc:"Identify and fix slow queries with execution plans.",skills:["EXPLAIN","Index Tuning","Query Rewriting"]}],
    interviewQuestions: [{q:"What is the difference between WHERE and HAVING?",a:"WHERE filters rows before grouping (no aggregate functions). HAVING filters groups after GROUP BY (can use aggregate functions). WHERE is processed first in the query execution order.",diff:"Easy"},{q:"Explain different JOIN types.",a:"INNER JOIN: matching rows from both tables. LEFT JOIN: all left rows + matching right rows (NULLs if no match). RIGHT JOIN: all right rows + matching left rows. FULL OUTER JOIN: all rows from both tables.",diff:"Easy"},{q:"What are window functions?",a:"Window functions perform calculations across a set of rows related to the current row without collapsing them (unlike GROUP BY). Examples: ROW_NUMBER(), RANK(), SUM() OVER (PARTITION BY ...).",diff:"Medium"},{q:"How do you optimize a slow query?",a:"Analyze with EXPLAIN/EXPLAIN ANALYZE. Add appropriate indexes. Avoid SELECT *. Rewrite subqueries as JOINs. Use CTEs for readability. Consider partitioning large tables. Update table statistics.",diff:"Medium"},{q:"What is database normalization?",a:"Normalization organizes data to reduce redundancy: 1NF (atomic values, no repeating groups), 2NF (1NF + no partial dependencies), 3NF (2NF + no transitive dependencies). Balances data integrity with query performance.",diff:"Medium"},{q:"Explain transactions and ACID properties.",a:"Transactions group operations into atomic units. ACID: Atomicity (all or nothing), Consistency (valid state transitions), Isolation (concurrent transactions don't interfere), Durability (committed data persists).",diff:"Hard"}],
