    resources: [{type:"W3Schools",title:"Learn Git on W3Schools",desc:"Interactive Git tutorial with examples and exercises.",link:"https://www.w3schools.com/git/"},{type:"Documentation",title:"Git Official Documentation",desc:"Comprehensive Git reference and tutorials.",link:"https://git-scm.com/doc"},{type:"Documentation",title:"GitHub Guides",desc:"Official GitHub tutorials and workflows.",link:"https://docs.github.com/en"},{type:"Tutorials",title:"Learn Git Branching",desc:"Interactive visual tutorial for Git branching.",link:"https://learngitbranching.js.org/"},{type:"Tutorials",title:"Pro Git Book (Free)",desc:"Complete Git reference book by Scott Chacon.",link:"https://git-scm.com/book/en/v2"},{type:"Videos",title:"Fireship - Git in 100 Seconds",desc:"Quick Git version control overview.",link:"https://www.youtube.com/watch?v=hwPq3U4pCj0"},{type:"Videos",title:"Traversy Media - Git Crash Course",desc:"Practical Git fundamentals for beginners.",link:"https://www.youtube.com/watch?v=SWYqp7iY_Tc"},{type:"Books",title:"Version Control with Git (2nd Ed)",desc:"Comprehensive guide to Git by Jon Loeliger.",link:"https://www.amazon.com/Version-Control-Git-Techniques-Professionals/dp/1449316387"},{type:"Books",title:"Git for Teams",desc:"Collaborative workflows and team practices.",link:"https://www.amazon.com/Git-Teams-Effective-Collaboration-Practices/dp/1491911182"}],
    projects: [{diff:"Beginner",name:"Personal Project with Git",desc:"Initialize a project and manage changes with Git.",skills:["init","commit","branching"]},{diff:"Beginner",name:"Collaborative Repository",desc:"Set up a shared repo with branching workflow.",skills:["clone","branch","merge","remote"]},{diff:"Intermediate",name:"Open Source Contribution",desc:"Contribute to an open source project via PRs.",skills:["fork","pull request","code review"]},{diff:"Intermediate",name:"Git Hooks Automation",desc:"Automate linting and formatting with pre-commit hooks.",skills:["hooks","husky","automation"]},{diff:"Advanced",name:"Monorepo Management",desc:"Manage multiple packages in a single repository.",skills:["monorepo","workspaces","Lerna"]},{diff:"Advanced",name:"CI/CD with Git",desc:"Automate testing and deployment on push events.",skills:["GitHub Actions","branching strategy","automation"]}],
    interviewQuestions: [{q:"What is the difference between git merge and git rebase?",a:"Merge creates a merge commit preserving full history. Rebase replays commits on top of another branch creating linear history. Merge is safer for shared branches; rebase is cleaner for local feature branches.",diff:"Medium"},{q:"Explain git stash.",a:"Git stash temporarily stores modified tracked files. It saves your working directory and index state, allowing you to work on something else and come back later. Use git stash pop to restore.",diff:"Easy"},{q:"What is a pull request?",a:"A pull request proposes changes from one branch to another. It enables code review, discussion, and automated testing before merging. Platform-specific to GitHub/GitLab/Bitbucket.",diff:"Easy"},{q:"How do you resolve merge conflicts?",a:"Git marks conflicts with <<<<<<<, =======, >>>>>>>. Edit files to keep desired changes, remove conflict markers, git add the resolved files, then commit. Tools like VS Code and IntelliJ provide visual merge tools.",diff:"Medium"},{q:"What is the difference between git reset --soft, --mixed, and --hard?",a:"--soft: moves HEAD only, changes stay in staging. --mixed: moves HEAD and unstages changes, changes stay in working dir. --hard: moves HEAD and discards all changes. Hard is destructive and irreversible.",diff:"Hard"},{q:"Explain the Git object model.",a:"Git stores four object types: blobs (file content), trees (directory structure), commits (snapshot + metadata), and tags (named references). All objects are SHA-1 hashed and content-addressable.",diff:"Hard"}],
