    resources: [{type:"W3Schools",title:"Learn AI on W3Schools",desc:"Interactive AI and machine learning tutorial with examples and exercises.",link:"https://www.w3schools.com/ai/"},{type:"Documentation",title:"Scikit-learn Documentation",desc:"Comprehensive ML library documentation.",link:"https://scikit-learn.org/stable/documentation.html"},{type:"Documentation",title:"Google ML Crash Course",desc:"Free ML course by Google engineers.",link:"https://developers.google.com/machine-learning/crash-course"},{type:"Tutorials",title:"Kaggle Learn",desc:"Hands-on ML tutorials with competitions.",link:"https://www.kaggle.com/learn"},{type:"Tutorials",title:"fast.ai - Practical Deep Learning",desc:"Top-down practical deep learning course.",link:"https://course.fast.ai/"},{type:"Videos",title:"3Blue1Brown - Neural Networks",desc:"Visual intuition for neural networks.",link:"https://www.youtube.com/playlist?list=PLZHQObOWTQDNU6R1_67000Dx_ZCJB-3pi"},{type:"Videos",title:"Fireship - ML in 100 Seconds",desc:"Quick overview of machine learning concepts.",link:"https://www.youtube.com/watch?v=i_LwzRVP7bg"},{type:"Books",title:"Hands-On ML with Scikit-Learn (2nd Ed)",desc:"Comprehensive practical ML guide.",link:"https://www.amazon.com/Hands-Machine-Learning-Scikit-Learn-TensorFlow/dp/1098125975"},{type:"Books",title:"An Introduction to Statistical Learning",desc:"Accessible statistics and ML textbook.",link:"https://www.statlearning.com/"}],
    projects: [{diff:"Beginner",name:"House Price Predictor",desc:"Predict housing prices using regression.",skills:["Linear Regression","Feature Engineering","Evaluation"]},{diff:"Beginner",name:"Spam Classifier",desc:"Classify emails as spam or ham.",skills:["NLP","Naive Bayes","Text Processing"]},{diff:"Intermediate",name:"Image Classifier",desc:"Build a CNN for flower classification.",skills:["CNN","Transfer Learning","Data Augmentation"]},{diff:"Intermediate",name:"Customer Segmentation",desc:"Cluster customers by behavior patterns.",skills:["K-Means","PCA","Visualization"]},{diff:"Advanced",name:"Sentiment Analysis API",desc:"Real-time sentiment analysis REST API.",skills:["BERT","FastAPI","Deployment"]},{diff:"Advanced",name:"Recommendation Engine",desc:"Build a movie recommendation system.",skills:["Collaborative Filtering","Matrix Factorization","Evaluation"]}],
    interviewQuestions: [{q:"Explain bias-variance tradeoff.",a:"Bias: error from overly simple models (underfitting). Variance: error from overly complex models (overfitting). Total error = bias^2 + variance + noise. Goal: find the sweet spot that minimizes total error.",diff:"Medium"},{q:"What is overfitting and how do you prevent it?",a:"Overfitting: model performs well on training data but poorly on test data. Prevention: cross-validation, regularization (L1/L2), dropout, early stopping, data augmentation, simpler model architecture, more training data.",diff:"Easy"},{q:"Explain gradient descent.",a:"Gradient descent optimizes model parameters by iteratively moving in the direction of steepest descent of the loss function. Learning rate controls step size. Variants: batch, stochastic (SGD), mini-batch.",diff:"Medium"},{q:"What is the difference between L1 and L2 regularization?",a:"L1 (Lasso): adds absolute value of weights to loss, promotes sparsity (feature selection). L2 (Ridge): adds squared weights, shrinks all weights evenly. L1 can zero out features; L2 keeps all but reduces their influence.",diff:"Medium"},{q:"How does a Random Forest work?",a:"Random Forest builds multiple decision trees on random subsets of data and features. Each tree votes; the majority wins. Reduces overfitting through ensemble averaging and feature randomization.",diff:"Easy"},{q:"What is transfer learning?",a:"Transfer learning uses a pre-trained model (trained on large dataset) as a starting point for a new task. Fine-tune the last layers on your specific data. Saves training time and data. Common in NLP (BERT) and vision (ResNet).",diff:"Medium"}],
