    resources: [{type:"W3Schools",title:"Learn Data Analysis on W3Schools",desc:"Interactive data analysis tutorial with examples and exercises.",link:"https://www.w3schools.com/analysis/"},{type:"Documentation",title:"Pandas Documentation",desc:"Comprehensive pandas library reference.",link:"https://pandas.pydata.org/docs/"},{type:"Documentation",title:"NumPy Documentation",desc:"NumPy array operations and functions.",link:"https://numpy.org/doc/"},{type:"Tutorials",title:"Kaggle - Data Analysis Course",desc:"Hands-on data analysis with Python.",link:"https://www.kaggle.com/learn/pandas"},{type:"Tutorials",title:"DataCamp - Data Analyst Track",desc:"Structured data analyst learning path.",link:"https://www.datacamp.com/tracks/data-analyst-with-python"},{type:"Videos",title:"Keith Galli - Data Analysis",desc:"Python data analysis tutorials with projects.",link:"https://www.youtube.com/@KeithGalli"},{type:"Videos",title:"Fireship - Data Analysis in 100 Seconds",desc:"Quick overview of data analysis concepts.",link:"https://www.youtube.com/watch?v=5ABpq3hB7Rc"},{type:"Books",title:"Python for Data Analysis (3rd Ed)",desc:"Wes McKinney's guide to pandas.",link:"https://www.amazon.com/Python-Data-Analysis-Wes-McKinney/dp/1492047545"},{type:"Books",title:"Storytelling with Data",desc:"Data visualization and communication guide.",link:"https://www.amazon.com/Storytelling-Data-Visualization-Decision-Makers/dp/1119621496"}],
    projects: [{diff:"Beginner",name:"Sales Data Exploration",desc:"Analyze sales trends with pandas and matplotlib.",skills:["Pandas","Visualization","Statistics"]},{diff:"Beginner",name:"Survey Results Analysis",desc:"Process and visualize survey response data.",skills:["Data Cleaning","Grouping","Charts"]},{diff:"Intermediate",name:"Customer Cohort Analysis",desc:"Track customer retention over time.",skills:["Time Series","Cohorts","SQL"]},{diff:"Intermediate",name:"A/B Test Analysis",desc:"Analyze experiment results with statistical tests.",skills:["Statistics","Hypothesis Testing","Power Analysis"]},{diff:"Advanced",name:"Executive Dashboard",desc:"Build an interactive dashboard for stakeholders.",skills:["Tableau/Power BI","KPIs","Storytelling"]},{diff:"Advanced",name:"Marketing Attribution Model",desc:"Multi-touch attribution for marketing channels.",skills:["SQL","Python","Statistical Modeling"]}],
    interviewQuestions: [{q:"What is the difference between correlation and causation?",a:"Correlation: two variables move together. Causation: one variable causes the other. Correlation does not imply causation. Establish causation through controlled experiments (A/B tests), not observational data alone.",diff:"Easy"},{q:"How do you handle missing data?",a:"Options: delete (listwise/pairwise), impute (mean/median/mode, forward fill, interpolation), or model (use ML to predict missing values). Choice depends on mechanism: MCAR, MAR, or MNAR.",diff:"Medium"},{q:"Explain the types of data analysis.",a:"Descriptive: what happened (historical). Diagnostic: why it happened (root cause). Predictive: what will happen (forecasting). Prescriptive: what should we do (recommendations). Each builds on the previous.",diff:"Easy"},{q:"What makes a good data visualization?",a:"Clear title and labels, appropriate chart type for the data, minimal clutter, honest representation (no misleading axes), accessible colors, focus on the insight, and appropriate level of detail for the audience.",diff:"Medium"},{q:"How do you design a dashboard?",a:"Start with the audience and their questions. Choose KPIs that matter. Organize from summary to detail. Use consistent formatting. Ensure real-time accuracy. Make it interactive. Test with actual users.",diff:"Medium"},{q:"What is A/B testing and when should you use it?",a:"A/B testing compares two versions to determine which performs better. Use for: button colors, page layouts, feature changes. Requires: clear hypothesis, sufficient sample size, random assignment, and statistical significance.",diff:"Easy"}],
