    resources: [{type:"W3Schools",title:"Learn Linux on W3Schools",desc:"Interactive Linux tutorial with examples and exercises.",link:"https://www.w3schools.com/linux/"},{type:"Documentation",title:"Linux man-pages",desc:"Official Linux manual pages.",link:"https://man7.org/linux/man-pages/"},{type:"Documentation",title:"The Linux Documentation Project",desc:"Guides, howtos, and documentation.",link:"https://tldp.org/"},{type:"Tutorials",title:"Linux Journey",desc:"Free interactive Linux learning.",link:"https://linuxjourney.com/"},{type:"Tutorials",title:"OverTheWire: Bandit",desc:"Learn Linux by solving security wargames.",link:"https://overthewire.org/wargames/bandit/"},{type:"Videos",title:"Fireship - Linux in 100 Seconds",desc:"Quick Linux overview.",link:"https://www.youtube.com/watch?v=sWbUDq4S6Y8"},{type:"Videos",title:"NetworkChuck - Linux Course",desc:"Practical Linux for beginners.",link:"https://www.youtube.com/@NetworkChuck"},{type:"Books",title:"The Linux Command Line (2nd Ed)",desc:"Complete guide by William Shotts.",link:"https://www.amazon.com/Linux-Command-Line-2nd-Introduction/dp/1593279523"},{type:"Books",title:"How Linux Works (3rd Ed)",desc:"Deep dive into Linux internals.",link:"https://www.amazon.com/How-Linux-Works-System-Administrators/dp/1718502702"}],
    projects: [{diff:"Beginner",name:"Shell Script Toolbox",desc:"Create utility scripts for common tasks.",skills:["Bash","Variables","Conditionals"]},{diff:"Beginner",name:"Server Setup",desc:"Set up and configure a Linux server.",skills:["SSH","Packages","Firewall"]},{diff:"Intermediate",name:"Automated Backup System",desc:"Cron-based backup with rotation.",skills:["Cron","rsync","Compression"]},{diff:"Intermediate",name:"Log Analyzer",desc:"Parse and analyze system logs.",skills:["grep","sed","awk","Statistics"]},{diff:"Advanced",name:"Web Server from Scratch",desc:"Configure Nginx with SSL and reverse proxy.",skills:["Nginx","SSL","Configuration"]},{diff:"Advanced",name:"Performance Monitoring",desc:"Build a system monitoring dashboard.",skills:["vmstat","iostat","Custom Scripts"]}],
    interviewQuestions: [{q:"What is the difference between a process and a thread?",a:"Process: independent execution with own memory space. Thread: lightweight process sharing memory within a process. Processes are isolated; threads share resources. Use processes for isolation, threads for shared-state concurrency.",diff:"Medium"},{q:"Explain Linux file permissions.",a:"Three groups: owner, group, others. Three permissions: read (r=4), write (w=2), execute (x=1). chmod 755 = rwxr-xr-x. Use chmod to change, chown to change owner. Special: SUID, SGID, sticky bit.",diff:"Easy"},{q:"What is a zombie process?",a:"A zombie process has completed execution but still has an entry in the process table. Occurs when parent hasn't called wait() to read its exit status. Use ps to find them; kill parent to clean up.",diff:"Hard"},{q:"How does Linux manage memory?",a:"Linux uses virtual memory with paging. Physical RAM is divided into pages. Swap space extends RAM to disk. Page cache caches file data. OOM killer terminates processes when memory is exhausted.",diff:"Hard"},{q:"What is the purpose of /etc/fstab?",a:"fstab defines filesystem mount points, options, and order. It's read at boot to mount filesystems automatically. Configure mounts, swap, and network filesystems here.",diff:"Medium"},{q:"Explain the Linux boot process.",a:"BIOS/UEFI -> Bootloader (GRUB) -> Kernel load -> initramfs -> systemd/PID 1 -> default.target (multi-user or graphical). Each stage prepares the system for the next.",diff:"Hard"}],
